<template>
  <div class="profile-container">
    <el-row :gutter="20">
      <el-col :span="24">
        <div class="page-header">
          <h1>个人资料</h1>
        </div>
      </el-col>
    </el-row>
    
    <el-row :gutter="20">
      <el-col :xs="24" :md="16">
        <el-card class="profile-card" v-loading="isLoading">
          <template #header>
            <div class="card-header">
              <h3>基本信息</h3>
            </div>
          </template>
          
          <el-form 
            ref="profileForm" 
            :model="formData" 
            :rules="rules" 
            label-position="top"
            @submit.prevent="handleSaveProfile"
          >
            <el-alert
              v-if="error"
              :title="error"
              type="error"
              :closable="false"
              show-icon
              class="profile-alert"
            />
            
            <el-form-item label="用户名" prop="username">
              <el-input 
                v-model="formData.username" 
                placeholder="用户名"
                disabled
              />
            </el-form-item>
            
            <el-form-item label="电子邮箱" prop="email">
              <el-input 
                v-model="formData.email" 
                placeholder="电子邮箱"
                type="email"
              />
            </el-form-item>
            
            <el-form-item label="名字" prop="first_name">
              <el-input 
                v-model="formData.first_name" 
                placeholder="名字"
              />
            </el-form-item>
            
            <el-form-item label="姓氏" prop="last_name">
              <el-input 
                v-model="formData.last_name" 
                placeholder="姓氏"
              />
            </el-form-item>
            
            <el-form-item>
              <el-button 
                type="primary" 
                native-type="submit" 
                :loading="isLoading"
              >
                保存
              </el-button>
            </el-form-item>
          </el-form>
        </el-card>
      </el-col>
      
      <el-col :xs="24" :md="8">
        <el-card class="security-card">
          <template #header>
            <div class="card-header">
              <h3>安全设置</h3>
            </div>
          </template>
          
          <div class="security-item">
            <h4>修改密码</h4>
            <p>定期更改密码可以提高账户安全性</p>
            <el-button 
              type="primary" 
              plain
              @click="showPasswordDialog = true"
            >
              修改密码
            </el-button>
          </div>
          
          <div class="security-item">
            <h4>账户活动</h4>
            <p>查看您的账户登录记录和操作历史</p>
            <el-button 
              type="info" 
              plain
              @click="$router.push('/profile/activity')"
            >
              查看活动
            </el-button>
          </div>
        </el-card>
      </el-col>
    </el-row>
    
    <!-- 修改密码对话框 -->
    <el-dialog
      v-model="showPasswordDialog"
      title="修改密码"
      width="30%"
    >
      <el-form 
        ref="passwordForm" 
        :model="passwordData" 
        :rules="passwordRules" 
        label-position="top"
      >
        <el-form-item label="当前密码" prop="old_password">
          <el-input 
            v-model="passwordData.old_password" 
            type="password" 
            placeholder="请输入当前密码"
            show-password
          />
        </el-form-item>
        
        <el-form-item label="新密码" prop="new_password1">
          <el-input 
            v-model="passwordData.new_password1" 
            type="password" 
            placeholder="请输入新密码"
            show-password
          />
        </el-form-item>
        
        <el-form-item label="确认新密码" prop="new_password2">
          <el-input 
            v-model="passwordData.new_password2" 
            type="password" 
            placeholder="请再次输入新密码"
            show-password
          />
        </el-form-item>
      </el-form>
      
      <template #footer>
        <span class="dialog-footer">
          <el-button @click="showPasswordDialog = false">取消</el-button>
          <el-button 
            type="primary" 
            @click="handleChangePassword"
            :loading="passwordLoading"
          >
            确认修改
          </el-button>
        </span>
      </template>
    </el-dialog>
  </div>
</template>

<script>
import { ref, reactive, computed, onMounted } from 'vue'
import { useAuthStore } from '@/store/auth'
import { ElMessage } from 'element-plus'
import axios from 'axios'

export default {
  name: 'ProfileView',
  setup() {
    const authStore = useAuthStore()
    const profileForm = ref(null)
    const passwordForm = ref(null)
    
    // 表单数据
    const formData = reactive({
      username: '',
      email: '',
      first_name: '',
      last_name: ''
    })
    
    // 密码表单数据
    const passwordData = reactive({
      old_password: '',
      new_password1: '',
      new_password2: ''
    })
    
    // 状态
    const showPasswordDialog = ref(false)
    const passwordLoading = ref(false)
    
    // 验证两次密码是否一致
    const validatePassConfirm = (rule, value, callback) => {
      if (value !== passwordData.new_password1) {
        callback(new Error('两次输入的密码不一致'))
      } else {
        callback()
      }
    }
    
    // 表单校验规则
    const rules = {
      email: [
        { required: true, message: '请输入电子邮箱', trigger: 'blur' },
        { type: 'email', message: '请输入正确的电子邮箱格式', trigger: 'blur' }
      ]
    }
    
    // 密码校验规则
    const passwordRules = {
      old_password: [
        { required: true, message: '请输入当前密码', trigger: 'blur' }
      ],
      new_password1: [
        { required: true, message: '请输入新密码', trigger: 'blur' },
        { min: 6, message: '密码长度不能小于6个字符', trigger: 'blur' }
      ],
      new_password2: [
        { required: true, message: '请再次输入新密码', trigger: 'blur' },
        { validator: validatePassConfirm, trigger: 'blur' }
      ]
    }
    
    // 计算属性
    const isLoading = computed(() => authStore.isLoading)
    const error = computed(() => authStore.error)
    
    // 获取用户个人资料
    const fetchUserProfile = async () => {
      if (!authStore.user) {
        await authStore.checkAuth()
      }
      
      if (authStore.user) {
        formData.username = authStore.user.username || ''
        formData.email = authStore.user.email || ''
        formData.first_name = authStore.user.first_name || ''
        formData.last_name = authStore.user.last_name || ''
      }
    }
    
    // 保存个人资料
    const handleSaveProfile = async () => {
      if (!profileForm.value) return
      
      try {
        await profileForm.value.validate()
        
        const response = await axios.patch('/api/users/profile/', {
          email: formData.email,
          first_name: formData.first_name,
          last_name: formData.last_name
        })
        
        // 更新本地用户数据
        if (response.data) {
          authStore.user = {
            ...authStore.user,
            ...response.data
          }
        }
        
        ElMessage.success('个人资料更新成功')
      } catch (error) {
        ElMessage.error('更新个人资料失败：' + (error.response?.data?.message || error.message || '未知错误'))
      }
    }
    
    // 修改密码
    const handleChangePassword = async () => {
      if (!passwordForm.value) return
      
      try {
        await passwordForm.value.validate()
        passwordLoading.value = true
        
        await axios.post('/api/users/change-password/', passwordData)
        ElMessage.success('密码修改成功')
        
        // 重置表单并关闭对话框
        passwordData.old_password = ''
        passwordData.new_password1 = ''
        passwordData.new_password2 = ''
        showPasswordDialog.value = false
      } catch (error) {
        ElMessage.error('修改密码失败：' + (error.response?.data?.message || error.message || '未知错误'))
      } finally {
        passwordLoading.value = false
      }
    }
    
    // 生命周期钩子
    onMounted(() => {
      fetchUserProfile()
    })
    
    return {
      profileForm,
      passwordForm,
      formData,
      passwordData,
      rules,
      passwordRules,
      isLoading,
      error,
      showPasswordDialog,
      passwordLoading,
      handleSaveProfile,
      handleChangePassword
    }
  }
}
</script>

<style scoped>
.profile-container {
  max-width: 1200px;
  margin: 0 auto;
  padding: 20px;
}

.page-header {
  margin-bottom: 20px;
}

.profile-card, .security-card {
  margin-bottom: 20px;
}

.card-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
}

.profile-alert {
  margin-bottom: 20px;
}

.security-item {
  padding: 15px 0;
  border-bottom: 1px solid #eee;
}

.security-item:last-child {
  border-bottom: none;
}

.security-item h4 {
  margin: 0 0 10px 0;
}

.security-item p {
  color: #606266;
  margin-bottom: 10px;
}
</style> 